changeSet.sql:
UPDATE config_comercial SET mensagem_preco = REPLACE(mensagem_preco, 'Semear App', 'WillIgreja')
WHERE mensagem_preco LIKE '%Semear App%';
UPDATE config_comercial SET mensagem_preco = REPLACE(mensagem_preco, 'plano Semear Completo', 'Plano Completo')
WHERE mensagem_preco LIKE '%Semear Completo%';
UPDATE config_comercial SET mensagem_fim_teste = REPLACE(mensagem_fim_teste, 'Semear App', 'WillIgreja')
WHERE mensagem_fim_teste LIKE '%Semear App%';
UPDATE config_comercial SET mensagem_fim_teste = REPLACE(mensagem_fim_teste, 'plano Semear Completo', 'Plano Completo')
WHERE mensagem_fim_teste LIKE '%Semear Completo%';
